Do 'get'
If &MostrarVazio = Status_SimNao.Sim If &TotMovItmVlr > 0 &SdtAnalise.Add(&SdtAnaliseitem) EndIf Else &SdtAnalise.Add(&SdtAnaliseitem) EndIf EndIf EndFor //################################################## CRÉDITO ##################### &SdtAnaliseitem = new() &SdtAnaliseitem.PlanCod = random() &SdtAnaliseitem.PlanCodNom = 'TOTAL CRÉDITO' &SdtAnaliseitem.PlanNom = 'CRÉDITO' &SdtAnaliseitem.PlanHie = '' &SdtAnaliseitem.PlanCatTip = 'C' &SdtAnaliseitem.PlanAnaSin = 'A' &SdtAnaliseitem.Janeiro = &TotCreJan &SdtAnaliseitem.Favereiro = &TotCreFev &SdtAnaliseitem.Marco = &TotCreMar &SdtAnaliseitem.Abril = &TotCreAbr &SdtAnaliseitem.Maio = &TotCreMai &SdtAnaliseitem.Junho = &TotCreJun &SdtAnaliseitem.Julho = &TotCreJul &SdtAnaliseitem.Agosto = &TotCreAgo &SdtAnaliseitem.Setembro = &TotCreSet &SdtAnaliseitem.Outubro = &TotCreOut &SdtAnaliseitem.Novembro = &TotCreNov &SdtAnaliseitem.Dezembro = &TotCreDez &SdtAnaliseitem.TotalAno = &TotCreCre
