//################################################## SALDO TOTAL ##################### &SdtAnaliseitem = new() &SdtAnaliseitem.PlanCod = random() &SdtAnaliseitem.PlanCodNom = 'SALDO DO MÊS' &SdtAnaliseitem.PlanNom = 'SALDO DO MÊS' &SdtAnaliseitem.PlanHie = '' &SdtAnaliseitem.PlanCatTip = '' &SdtAnaliseitem.PlanAnaSin = 'A' &SdtAnaliseitem.Janeiro = &TotCreJan - &TotDebJan &SdtAnaliseitem.Favereiro = &TotCreFev - &TotDebFev &SdtAnaliseitem.Marco = &TotCreMar - &TotDebMar &SdtAnaliseitem.Abril = &TotCreAbr - &TotDebAbr &SdtAnaliseitem.Maio = &TotCreMai - &TotDebMai &SdtAnaliseitem.Junho = &TotCreJun - &TotDebJun &SdtAnaliseitem.Julho = &TotCreJul - &TotDebJul &SdtAnaliseitem.Agosto = &TotCreAgo - &TotDebAgo &SdtAnaliseitem.Setembro = &TotCreSet - &TotDebSet &SdtAnaliseitem.Outubro = &TotCreOut - &TotDebOut &SdtAnaliseitem.Novembro = &TotCreNov - &TotDebNov &SdtAnaliseitem.Dezembro = &TotCreDez - &TotDebDez &SdtAnaliseitem.TotalAno = &TotCreCre - &TotDebDeb // &TotalAno = &TotCreCre - &TotDebDeb // // If &MostrarVazio = Status_SimNao.Sim // If &TotalAno > 0 // &SdtAnalise.Add(&SdtAnaliseitem) // EndIf // Else &SdtAnalise.Add(&SdtAnaliseitem) // EndIf //&XmlWhiter.Open('analise.xml') //&XmlWhiter.WriteRawText(&SdtAnalise.ToXml()) //&XmlWhiter.Close() //################################################################################
Sub 'get' &TotMovItmVlr = 0 For each order EmpCod,PlanCod, FinAno, FinMes Where EmpCod = &EmpCod Where PlanCod = &auxPlanCod Where FinAno = &Ano Do Case Case FinMes = 1 &SdtAnaliseitem.Janeiro += FinVlr If PlanCatTip = 'C' &TotCreJan += FinVlr Else &TotDebJan += FinVlr EndIf Case FinMes = 2 &SdtAnaliseitem.Favereiro += FinVlr If PlanCatTip = 'C' &TotCreFev += FinVlr Else &TotDebFev += FinVlr EndIf Case FinMes = 3 &SdtAnaliseitem.Marco += FinVlr If PlanCatTip = 'C' &TotCreMar += FinVlr Else &TotDebMar += FinVlr EndIf Case FinMes = 4 &SdtAnaliseitem.Abril+= FinVlr If PlanCatTip = 'C' &TotCreAbr += FinVlr Else &TotDebAbr += FinVlr EndIf Case FinMes = 5 &SdtAnaliseitem.Maio += FinVlr If PlanCatTip = 'C' &TotCreMai += FinVlr Else &TotDebMai += FinVlr EndIf Case FinMes = 6 &SdtAnaliseitem.Junho += FinVlr If PlanCatTip = 'C' &TotCreJun += FinVlr Else &TotDebJun += FinVlr EndIf Case FinMes = 7 &SdtAnaliseitem.Julho += FinVlr If PlanCatTip = 'C' &TotCreJul += FinVlr Else &TotDebJul += FinVlr EndIf Case FinMes = 8 &SdtAnaliseitem.Agosto += FinVlr If PlanCatTip = 'C' &TotCreAgo += FinVlr Else &TotDebAgo += FinVlr EndIf Case FinMes = 9 &SdtAnaliseitem.Setembro += FinVlr If PlanCatTip = 'C' &TotCreSet += FinVlr Else &TotDebSet += FinVlr EndIf Case FinMes = 10 &SdtAnaliseitem.Outubro += FinVlr If PlanCatTip = 'C' &TotCreOut += FinVlr Else &TotDebOut += FinVlr EndIf Case FinMes = 11 &SdtAnaliseitem.Novembro += FinVlr If PlanCatTip = 'C' &TotCreNov += FinVlr Else &TotDebNov += FinVlr EndIf Case FinMes = 12 &SdtAnaliseitem.Dezembro += FinVlr If PlanCatTip = 'C' &TotCreDez += FinVlr Else &TotDebDez += FinVlr EndIf EndCase &SdtAnaliseitem.TotalAno += FinVlr &TotMovItmVlr += FinVlr If PlanCatTip = 'C' &TotCreCre += FinVlr Else &TotDebDeb += FinVlr EndIf EndFor EndSub
